import React, { useEffect, useState } from "react";
import Dashboard from "./Dashboard";

export default function TaskList() {
  const [tasks, setTasks] = useState([]);
  const [title, setTitle] = useState("");
  const [dueDate, setDueDate] = useState("");
  const [notifications, setNotifications] = useState([]);

  const fetchAll = async () => {
    try {
      const t = await fetch("http://localhost:8086/tasks").then(r => r.json());
      const n = await fetch("http://localhost:8086/tasks/notifications").then(r => r.json());

      setTasks(t);
      setNotifications(n);
    } catch (err) {
      console.error("Error fetching data:", err);
    }
  };

  useEffect(() => { fetchAll(); }, []);

  const addTask = async () => {
    if (!title || !dueDate) {
      alert("Please fill all fields");
      return;
    }

    try {
      await fetch("http://localhost:8086/tasks", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ title, dueDate })
      });

      setTitle("");
      setDueDate("");
      fetchAll();
    } catch (err) {
      console.error("Error adding task:", err);
    }
  };

  const suggest = async () => {
    try {
      await fetch("http://localhost:8086/tasks/suggest", { method: "POST" });
      fetchAll();
    } catch (err) {
      console.error("Error suggesting task:", err);
    }
  };

  const completeTask = async (id) => {
    await fetch(`http://localhost:8086/tasks/${id}/complete`, {
      method: "PUT"
    });
    fetchAll();
  };

  return (
    <div className="p-6 text-white">
      <Dashboard />

      {/* Notifications */}
      {notifications.length > 0 && (
        <div className="bg-red-500 p-3 rounded mb-4">
          ⚠ {notifications.length} tasks due soon!
        </div>
      )}

      {/* Add Task */}
      <div className="flex gap-2 mb-4">
        <input
          value={title}
          onChange={e => setTitle(e.target.value)}
          placeholder="Task"
          className="px-3 py-2 bg-white/20 rounded"
        />

        <input
          type="date"
          value={dueDate}
          onChange={e => setDueDate(e.target.value)}
          className="px-3 py-2 bg-white/20 rounded"
        />

        <button onClick={addTask} className="bg-blue-500 px-3 rounded">
          Add
        </button>
      </div>

      <button
        onClick={suggest}
        className="bg-purple-500 px-4 py-2 rounded mb-4"
      >
        AI Suggest
      </button>

      {/* Tasks */}
      {tasks.map(t => (
        <div key={t.id} className="bg-white/10 p-3 mb-2 rounded flex justify-between">
          <div>
            <div>{t.title}</div>
            <div className="text-sm text-gray-300">
              {t.priority} | {t.dueDate}
            </div>
          </div>

          {!t.completed && (
            <button
              onClick={() => completeTask(t.id)}
              className="bg-green-500 px-3 rounded"
            >
              Done
            </button>
          )}
        </div>
      ))}
    </div>
  );
}
